out=[]
for start,end,matn,_,context in spans:
    citation='Hadeeth'
    if re.search(r'قال الله|قال تعالى|قال الله تعالى|سورة|آية|سَبَّحَ|قالَ اللَّهُ', context):
        citation='Aya'
    if re.search(r'قال النبي|قال الرسول|النبي محمد|قال النبي محمد|قال رسول الله|في الحديث|رواه|روى|قال النبي محمد صلى الله|قال النبي صلى الله', context):
        # if both cues present, prefer Aya (handled above)
        if 'قال الله' in context or 'قال تعالى' in context or 'سورة' in context:
            citation=citation
        else:
            citation='Hadeeth'
    out.append({"span_start":start,"span_end":end,"span_text":matn,"citation_type": "Aya" if citation=='Aya' else "Hadeeth"})
import json
print(json.dumps(out,ensure_ascii=False,indent=2))
